package org.apache.commons.math.linear;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/org/apache/commons/math/linear/",
    glue = "org.apache.commons.math.linear.steps",
    tags = "@math209 or @bug"
)
public class CucumberTest {
}

package org.apache.commons.math.linear;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import static org.junit.Assert.*;

import java.math.BigDecimal;

public class StepDefs {

    private BigMatrix bigMatrix;
    private RealMatrix realMatrix;
    private BigDecimal[] bigResult;
    private double[] realResult;
    private BigDecimal[] bigVector;
    private double[] realVector;

    @Given("a BigMatrix with values {string}")
    public void a_BigMatrix_with_values(String matrixValues) {
        // Parse matrix string like "[[1, 2], [3, 4], [5, 6]]"
        String cleanValues = matrixValues.replaceAll("[\\[\\]]", "");
        String[] rows = cleanValues.split("\\], \\[");

        BigDecimal[][] matrixData = new BigDecimal[rows.length][];
        for (int i = 0; i < rows.length; i++) {
            String[] elements = rows[i].trim().split(", ");
            matrixData[i] = new BigDecimal[elements.length];
            for (int j = 0; j < elements.length; j++) {
                matrixData[i][j] = new BigDecimal(elements[j].trim());
            }
        }

        bigMatrix = new BigMatrixImpl(matrixData, false);
    }

    @Given("a RealMatrix with values {string}")
    public void a_RealMatrix_with_values(String matrixValues) {
        // Parse matrix string like "[[1, 2], [3, 4], [5, 6]]"
        String cleanValues = matrixValues.replaceAll("[\\[\\]]", "");
        String[] rows = cleanValues.split("\\], \\[");

        double[][] matrixData = new double[rows.length][];
        for (int i = 0; i < rows.length; i++) {
            String[] elements = rows[i].trim().split(", ");
            matrixData[i] = new double[elements.length];
            for (int j = 0; j < elements.length; j++) {
                matrixData[i][j] = Double.parseDouble(elements[j].trim());
            }
        }

        realMatrix = new RealMatrixImpl(matrixData, false);
    }

    @When("I operate with vector {string}")
    public void i_operate_with_vector(String vectorValues) {
        // Parse vector string like "[1, 1]"
        String cleanValues = vectorValues.replaceAll("[\\[\\]]", "");
        String[] elements = cleanValues.trim().split(", ");

        // Set up both big and real vectors
        bigVector = new BigDecimal[elements.length];
        realVector = new double[elements.length];

        for (int i = 0; i < elements.length; i++) {
            bigVector[i] = new BigDecimal(elements[i].trim());
            realVector[i] = Double.parseDouble(elements[i].trim());
        }

        try {
            if (bigMatrix != null) {
                bigResult = bigMatrix.operate(bigVector);
            }
            if (realMatrix != null) {
                realResult = realMatrix.operate(realVector);
            }
        } catch (Exception e) {
            // Catch any exceptions that might occur during the operation
            System.out.println("Exception during operation: " + e.getMessage());
        }
    }

    @Then("the result should be {string}")
    public void the_result_should_be(String expectedResult) {
        // Parse expected result string like "[3.0, 7.0, 11.0]"
        String cleanValues = expectedResult.replaceAll("[\\[\\]]", "");
        String[] elements = cleanValues.trim().split(", ");
        double[] expected = new double[elements.length];

        for (int i = 0; i < elements.length; i++) {
            expected[i] = Double.parseDouble(elements[i].trim());
        }

        // Check both big and real results if they exist
        if (bigResult != null) {
            assertEquals("BigMatrix result length should match", expected.length, bigResult.length);
            for (int i = 0; i < expected.length; i++) {
                assertEquals("BigMatrix result[" + i + "] should match", expected[i], bigResult[i].doubleValue(), 1.0e-12);
            }
        }

        if (realResult != null) {
            assertEquals("RealMatrix result length should match", expected.length, realResult.length);
            for (int i = 0; i < expected.length; i++) {
                assertEquals("RealMatrix result[" + i + "] should match", expected[i], realResult[i], 1.0e-12);
            }
        }
    }

    @Given("a {int}x{int} matrix")
    public void a_x_matrix(int rows, int cols) {
        // Create a matrix with specified dimensions (fill with 1s for testing)
        BigDecimal[][] bigData = new BigDecimal[rows][cols];
        double[][] realData = new double[rows][cols];

        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                bigData[i][j] = new BigDecimal(i * cols + j + 1); // 1, 2, 3, etc.
                realData[i][j] = i * cols + j + 1;
            }
        }

        bigMatrix = new BigMatrixImpl(bigData, false);
        realMatrix = new RealMatrixImpl(realData, false);
    }

    @Then("the result should be a {int}-element vector")
    public void the_result_should_be_a_element_vector(int expectedLength) {
        if (bigResult != null) {
            assertEquals("BigMatrix result should have correct length", expectedLength, bigResult.length);
        }
        if (realResult != null) {
            assertEquals("RealMatrix result should have correct length", expectedLength, realResult.length);
        }
    }
}
